import{_ as e,o as a,c as i,a as t}from"./app.1b0dcdd7.js";const f=JSON.parse('{"title":"TheOrangeWizard (and Amerikkalanein) v. AltRaid, Jan 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Charges","slug":"charges","link":"#charges","children":[]},{"level":2,"title":"Plea","slug":"plea","link":"#plea","children":[]},{"level":2,"title":"Facts of the Case","slug":"facts-of-the-case","link":"#facts-of-the-case","children":[]},{"level":2,"title":"Laws and Precedents","slug":"laws-and-precedents","link":"#laws-and-precedents","children":[]},{"level":2,"title":"Outcome","slug":"outcome","link":"#outcome","children":[]}],"relativePath":"government/court-cases-precedents/theorangewizard_(and_amerikkalanein)_v_altraid_jan_2018.md","lastUpdated":1666055355000}'),r={name:"government/court-cases-precedents/theorangewizard_(and_amerikkalanein)_v_altraid_jan_2018.md"},n=t('<h1 id="theorangewizard-and-amerikkalanein-v-altraid-jan-2018" tabindex="-1">TheOrangeWizard (and Amerikkalanein) v. AltRaid, Jan 2018 <a class="header-anchor" href="#theorangewizard-and-amerikkalanein-v-altraid-jan-2018" aria-hidden="true">#</a></h1><p><strong>Judge</strong>: Dr Oracle</p><p><strong>Date</strong>: 20th January 2018</p><p><em>The following details are copied verbatim from Dr Oracle&#39;s judgement-summary. Initially AltRaid selected Amerikkalanein to preside however due to the conflict of interest Oracle took over the case.</em></p><h2 id="charges" tabindex="-1">Charges <a class="header-anchor" href="#charges" aria-hidden="true">#</a></h2><p>AltRaid (Asuna) for the unlawful murder/pearling of two citizens, Councillor TheOrangeWizard and Councillor Amerikkalanein.</p><h2 id="plea" tabindex="-1">Plea <a class="header-anchor" href="#plea" aria-hidden="true">#</a></h2><p>Asuna maintains he is not guilty. He admits to his actions freely but does not accept a crime has been committed (and that this trial is essentially a farce).</p><h2 id="facts-of-the-case" tabindex="-1">Facts of the Case <a class="header-anchor" href="#facts-of-the-case" aria-hidden="true">#</a></h2><ul><li><p>Asuna has for a number of days pretended to be a raider/troll on the account Exalted_Demon, persistent enough to warrant perusal within Yoahtlan borders</p></li><li><p>Asuna killed and pearled Orange and Amerikka</p></li><li><p>Asuna released them immediately</p></li><li><p>No material losses were suffered</p></li><li><p>Asuna\u2019s defence for this action is the claim that is was a \u2018raid drill\u2019</p></li><li><p>This \u2018raid drill\u2019 had no notification to the populace or Yoahtl leadership</p></li></ul><h2 id="laws-and-precedents" tabindex="-1">Laws and Precedents <a class="header-anchor" href="#laws-and-precedents" aria-hidden="true">#</a></h2><ul><li><p>Government of Yoahtl v. Link2006; No matter the charges, unless you are being directly attacked or the town is being griefed, or it is a hostile foreigner, no player other than councillors or the alcuahtl or any person occupying a position of authority to pearl legally authorized by the council and alcuahtl may pearl people.</p></li><li><p>Sir Crowley committed a nearly identical act in a more severe manner and was not charged (effectively being pardoned by bgbba). This case is not about whether Asuna committed murder resulting in pearling \u2013 by his own admission he killed the aforementioned councillors. What is in question is whether murder resulting in no loss is acceptable as a raid drill. Precedent very clearly states that Asuna cannot pearl people without appropriate and explicit consent, this however conflicts with the informal pardon of Sir Crowley. It is my view that this scenario should have been explicitly clarified after the Crowley incident. That said: Official precedent from worked court cases MUST take priority over a casual decision to pardon by the Alcuahtl.</p></li></ul><h2 id="outcome" tabindex="-1">Outcome <a class="header-anchor" href="#outcome" aria-hidden="true">#</a></h2><p>I am instructing a LENIENT sentence for the following reasons:</p><ul><li><p>Post-Crowley clarity has not been provided on the subject of raid drills</p></li><li><p>Asuna has been a contributing member of Yoahtl, most notably in pearling Fran</p></li><li><p>No material losses occurred</p></li><li><p>There appears to have been no malicious intentions</p></li><li><p>Defensive weaknesses have been highlighted from the event</p></li></ul><p>I am instructing there MUST be a sentence because:</p><ul><li><p>Two Yoahtl citizens were pearled without permission</p></li><li><p>A significant amount of time was wasted in the persual of Exalted_Demon</p></li><li><p>Asuna appears to have expressed relatively little remorse for the hassle he has caused</p></li></ul><p>I therefore find Asuna guilty of murdering two citizens/councillors of Yoahtl without permission. I sentence him to 1 hour of trench digging (or similar).</p>',18),l=[n];function o(s,d,h,c,p,u){return a(),i("div",null,l)}const g=e(r,[["render",o]]);export{f as __pageData,g as default};
